<?php

declare(strict_types=1);

namespace App\Services\Payroll;
use App\Models\Payroll\PayrollRun; use App\Models\Payroll\PayslipSequence; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class PayrollWorkflowService { public function submit(PayrollRun $run,int $userId):void{DB::transaction(function()use($run,$userId){$run=PayrollRun::whereKey($run->id)->lockForUpdate()->firstOrFail(); if($run->status!=='calculated'&&$run->status!=='revision') throw ValidationException::withMessages(['run'=>'Payroll tidak dapat diajukan.']); $run->update(['status'=>'submitted','submitted_by'=>$userId,'submitted_at'=>now()]);});} public function approve(PayrollRun $run,int $userId):void{DB::transaction(function()use($run,$userId){$run=PayrollRun::whereKey($run->id)->lockForUpdate()->firstOrFail(); if($run->status!=='submitted') throw ValidationException::withMessages(['run'=>'Payroll tidak menunggu persetujuan.']); if((int)$run->submitted_by===$userId) throw ValidationException::withMessages(['run'=>'Pengaju tidak boleh menyetujui sendiri.']); $run->update(['status'=>'approved','approved_by'=>$userId,'approved_at'=>now()]);});} public function reject(PayrollRun $run,int $userId,string $reason):void{DB::transaction(fn()=>PayrollRun::whereKey($run->id)->lockForUpdate()->firstOrFail()->update(['status'=>'revision','rejected_by'=>$userId,'rejected_at'=>now(),'rejection_reason'=>$reason]));} public function finalize(PayrollRun $run,int $userId):void{DB::transaction(function()use($run,$userId){$run=PayrollRun::whereKey($run->id)->with('items')->lockForUpdate()->firstOrFail(); if($run->status!=='approved') throw ValidationException::withMessages(['run'=>'Payroll harus disetujui sebelum finalisasi.']); foreach($run->items as $item){ if(!$item->payslip_number){$seq=PayslipSequence::firstOrCreate(['year'=>now()->year,'month'=>now()->month],['last_number'=>0]); $seq->increment('last_number'); $item->update(['payslip_number'=>'SLP-'.now()->format('Ym').'-'.str_pad((string)$seq->last_number,5,'0',STR_PAD_LEFT),'status'=>'final']);}} $run->update(['status'=>'final','finalized_by'=>$userId,'finalized_at'=>now()]);});}}
